-- SPDX-License-Identifier: GPL-2.0-only
-- linux-rs pattern database — the SQLite form of the rule DB + kernel
-- census, per the original project proposal ("the database becomes the
-- real product"). Rules stay authored as rulesdb/rules/*.toml (git-
-- diffable, human-editable); this schema is a QUERYABLE INDEX built from
-- them plus the Phase 1 census data, regenerated by scripts/build_db.py,
-- never hand-edited.

-- ---- kernel census (from tmp/functions.jsonl, tmp/region_census.pkl) ----

CREATE TABLE functions (
    id INTEGER PRIMARY KEY,
    file TEXT NOT NULL,
    name TEXT NOT NULL,
    line INTEGER NOT NULL,
    fp_exact TEXT NOT NULL,       -- normalised whole-function fingerprint
    fp_shape TEXT NOT NULL,       -- structure-only fingerprint
    nodes INTEGER NOT NULL,
    ncalls INTEGER NOT NULL,
    is_static INTEGER NOT NULL,
    features TEXT NOT NULL        -- JSON array: asm/goto/switch/loop
);
CREATE INDEX idx_functions_fp_exact ON functions(fp_exact);
CREATE INDEX idx_functions_fp_shape ON functions(fp_shape);
CREATE INDEX idx_functions_file ON functions(file);
CREATE INDEX idx_functions_name ON functions(name);

-- Call edges. callee_name is the raw identifier from the AST — it is NOT
-- resolved to a specific functions.id at import time, because C name
-- resolution needs full linkage info (a `static` name can be reused
-- per-TU) that the Phase-1 fingerprinter didn't record. Use the
-- `call_edges` VIEW below for a best-effort resolved join (unambiguous
-- non-static names only); for static callees, filter callee_defs by file
-- yourself.
CREATE TABLE callees (
    function_id INTEGER NOT NULL REFERENCES functions(id),
    callee_name TEXT NOT NULL
);
CREATE INDEX idx_callees_function ON callees(function_id);
CREATE INDEX idx_callees_name ON callees(callee_name);

-- Reverse index, explicit: every definition site for a given name (a name
-- can have >1 row if multiple TUs define a `static` function of that
-- name — that ambiguity is real and must stay visible, not hidden).
CREATE INDEX idx_functions_name_lookup ON functions(name, is_static);

CREATE TABLE statement_families (
    fp TEXT PRIMARY KEY,          -- normalised statement fingerprint (or MACROSTMT:<name>)
    instance_count INTEGER NOT NULL,
    exemplar_file TEXT,
    exemplar_line INTEGER,
    exemplar_snippet TEXT
);
CREATE INDEX idx_stmtfam_count ON statement_families(instance_count DESC);

-- ---- cscope cross-reference (from tmp/cscope.out, over the same 2996-TU
-- pinned corpus as the fingerprint census — see scripts/import_cscope.py)
--
-- Closes the documented gap in `callees`/`call_edges` below: an AST
-- fingerprinter has no linker/whole-program knowledge, so it cannot tell
-- WHICH definition of a `static` function a given call resolves to when
-- multiple TUs define a same-named static fn. cscope has real whole-
-- corpus symbol-table knowledge and resolves this correctly (verified
-- 2026-07-16: lib/argv_split.c's static count_argc() query-mode -3
-- returns exactly its one real caller, no cross-TU false matches).

CREATE TABLE cscope_symbols (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    kind TEXT NOT NULL,      -- 'definition' | 'call' | 'assignment' | 'text'
    file TEXT NOT NULL,
    line INTEGER NOT NULL,
    context TEXT             -- the calling/enclosing function name, when cscope reports one
);
CREATE INDEX idx_cscope_name ON cscope_symbols(name);
CREATE INDEX idx_cscope_kind ON cscope_symbols(kind);
CREATE INDEX idx_cscope_file ON cscope_symbols(file);

-- ---- sparse diagnostics (from a LOCALLY-BUILT sparse, not the Fedora
-- package — see scripts/import_sparse.py and docs/patterns-db.md.
-- Fedora's sparse 0.6.4 cannot parse this kernel version at all
-- (rejects __typeof_unqual__, required by include/asm-generic/rwonce.h
-- and others); upstream kernel.org sparse HEAD (mirrored locally at
-- /mnt/2tb/git_mirror/sparse/) has __typeof_unqual__ support and parses
-- cleanly. The build lives entirely under tmp/ (gitignored, rebuilt on
-- demand) — never a vendored binary in this repo (decision, 2026-07-16).
--
-- Kernel-native semantic checks (address-space annotations, endianness,
-- context imbalance) that generic tools have no model for at all —
-- genuinely new information, not a re-derivation of anything else here.

CREATE TABLE sparse_diagnostics (
    id INTEGER PRIMARY KEY,
    file TEXT NOT NULL,
    line INTEGER NOT NULL,
    col INTEGER,
    severity TEXT NOT NULL,   -- 'warning' | 'error'
    message TEXT NOT NULL
);
CREATE INDEX idx_sparse_file ON sparse_diagnostics(file);
CREATE INDEX idx_sparse_severity ON sparse_diagnostics(severity);

-- ---- rule DB (from rulesdb/rules/*.toml) ----

CREATE TABLE rules (
    id TEXT PRIMARY KEY,          -- e.g. "fls-family"
    number INTEGER NOT NULL,      -- e.g. 6, from the filename prefix
    version INTEGER NOT NULL,
    tier INTEGER NOT NULL,
    category TEXT NOT NULL,
    match_c TEXT,
    match_family TEXT,
    emit_kind TEXT,
    emit_rust TEXT,
    derivation TEXT,
    oracle TEXT,
    human_review INTEGER NOT NULL,
    deferred INTEGER NOT NULL DEFAULT 0,   -- true if [status] block present (not yet applied)
    source_path TEXT NOT NULL              -- rulesdb/rules/NNNN-*.toml, for round-tripping to the authored file
);
CREATE INDEX idx_rules_tier ON rules(tier);
CREATE INDEX idx_rules_deferred ON rules(deferred);

CREATE TABLE rule_constraints (
    rule_id TEXT NOT NULL REFERENCES rules(id),
    constraint_text TEXT NOT NULL
);
CREATE TABLE rule_negatives (
    rule_id TEXT NOT NULL REFERENCES rules(id),
    negative_text TEXT NOT NULL
);
CREATE TABLE rule_evidence (
    rule_id TEXT NOT NULL REFERENCES rules(id),
    evidence_text TEXT NOT NULL
);
CREATE TABLE rule_validation_instances (
    rule_id TEXT NOT NULL REFERENCES rules(id),
    instance_text TEXT NOT NULL   -- "file:symbol" form as authored, not parsed further
);

-- ---- translation status (from linux-riscv/lib/**/*_rs.rs + git log) ----

CREATE TABLE translated_tus (
    c_file TEXT PRIMARY KEY,      -- relative to linux-riscv/, e.g. "lib/bcd.c"
    rs_file TEXT NOT NULL,
    landed_at TEXT,               -- commit date, ISO 8601
    patch_number INTEGER
);
CREATE INDEX idx_translated_tus_cfile ON translated_tus(c_file);

-- c2rust baseline/triage runs (scripts/run_c2rust_baseline.py): one row
-- per (c_file, run) so re-running after a c2rust fork fix shows progress
-- over time rather than overwriting history. outcome is c2rust's own
-- result, independent of translated_tus — a TU can be manually landed
-- AND separately have a c2rust attempt on record (e.g. as a differential
-- check, or from before it was hand-translated).
CREATE TABLE c2rust_attempts (
    id INTEGER PRIMARY KEY,
    c_file TEXT NOT NULL,          -- relative to linux-riscv/, e.g. "lib/bcd.c"
    run_at TEXT NOT NULL,          -- ISO 8601, when this baseline run happened
    outcome TEXT NOT NULL,         -- crash | no_output | dropped_decls | clean
    returncode INTEGER,
    warnings INTEGER,
    missing_top_level_nodes INTEGER,
    missing_children INTEGER,
    label_address_exprs INTEGER,
    rs_files_emitted INTEGER,
    c2rust_rev TEXT,               -- awtoau/c2rust git rev used for this run
    corpus_rev TEXT,                -- linux-riscv HEAD at run time (see corpus_rev() in run_c2rust_baseline.py)
    peak_rss_bytes INTEGER,         -- observed peak RSS for this transpile, feeds adaptive_job_count()
    duration_s REAL,
    notes TEXT
);
CREATE INDEX idx_c2rust_attempts_cfile ON c2rust_attempts(c_file);
CREATE INDEX idx_c2rust_attempts_outcome ON c2rust_attempts(outcome);

-- Per-declaration outcome: which of a file's own top-level functions
-- actually made it into the emitted Rust vs were silently dropped. A
-- file-level outcome (e.g. "dropped_decls") hides whether one function
-- was lost out of 40 or the whole file fell over; this is the ground
-- truth c2rust_regression_check.py diffs on and stable_files() (in
-- run_c2rust_baseline.py) keys its stability window on.
CREATE TABLE c2rust_decl_outcomes (
    id INTEGER PRIMARY KEY,
    attempt_id INTEGER NOT NULL REFERENCES c2rust_attempts(id),
    c_file TEXT NOT NULL,
    decl_name TEXT NOT NULL,
    translated INTEGER NOT NULL,
    c2rust_rev TEXT,
    corpus_rev TEXT,
    run_at TEXT NOT NULL
);
CREATE INDEX idx_c2rust_decl_outcomes_cfile ON c2rust_decl_outcomes(c_file);
CREATE INDEX idx_c2rust_decl_outcomes_rev ON c2rust_decl_outcomes(c2rust_rev);

-- Individual failure SIGNATURES extracted from each attempt's log —
-- one row per distinct (kind, detail) occurrence, so recurring failure
-- classes (e.g. "GNU address-of-label in _THIS_IP_", "panic at
-- conversion.rs:1024 TagTypeUnknown") surface as queryable patterns
-- across the whole corpus, not just per-file pass/fail counts
-- (2026-07-17: "extract the issues... so we get patterns of failures").
CREATE TABLE c2rust_failure_signatures (
    id INTEGER PRIMARY KEY,
    attempt_id INTEGER NOT NULL REFERENCES c2rust_attempts(id),
    c_file TEXT NOT NULL,
    kind TEXT NOT NULL,        -- panic | missing_top_level_node | missing_child |
                                -- label_address | ast_warning | other
    source_file TEXT,          -- header/file the failure was located in, if known
    source_line INTEGER,
    detail TEXT NOT NULL       -- the specific message/macro/tag, deduplicatable
);
CREATE INDEX idx_c2rust_failsig_cfile ON c2rust_failure_signatures(c_file);
CREATE INDEX idx_c2rust_failsig_kind ON c2rust_failure_signatures(kind);
CREATE INDEX idx_c2rust_failsig_detail ON c2rust_failure_signatures(detail);

-- The actual "patterns of failure" view: distinct failure signatures
-- ranked by how many TUs they block — this is the fix-prioritization
-- queue (fix the signature blocking the most files first). Scoped to
-- the MOST RECENT run_at only — c2rust_attempts accumulates history
-- across repeated baseline runs (that's the point, for progress
-- tracking), but "what should I fix next" should reflect current
-- state, not every run ever recorded mixed together.
CREATE VIEW c2rust_failure_patterns AS
SELECT s.kind, s.detail, COUNT(DISTINCT s.c_file) AS tus_affected,
       GROUP_CONCAT(DISTINCT s.c_file) AS example_files
FROM c2rust_failure_signatures s
JOIN c2rust_attempts a ON a.id = s.attempt_id
WHERE a.run_at = (SELECT MAX(run_at) FROM c2rust_attempts)
GROUP BY s.kind, s.detail
ORDER BY tus_affected DESC;

-- Same "latest run only" scoping for the outcome-summary use case
-- (dev.py-style progress dashboard: how many clean/crash/etc RIGHT NOW).
CREATE VIEW c2rust_latest_run_summary AS
SELECT outcome, COUNT(*) AS n
FROM c2rust_attempts
WHERE run_at = (SELECT MAX(run_at) FROM c2rust_attempts)
GROUP BY outcome
ORDER BY n DESC;

-- Per-file rustc compile-check outcomes for each c2rust_rev — populated
-- by scripts/check_c2rust_output_compiles.py after every compile-check run.
-- c2rust_regression_check.py diffs these rev-over-rev exactly as it diffs
-- c2rust_decl_outcomes for transpile-level regressions (a4 from the
-- pipeline-audit, awto-au/linux-rs#15).
CREATE TABLE c2rust_compile_outcomes (
    id INTEGER PRIMARY KEY,
    c2rust_rev TEXT NOT NULL,    -- awtoau/c2rust git rev compile-checked
    run_at TEXT NOT NULL,        -- ISO 8601, when this compile-check run happened
    rs_file TEXT NOT NULL,       -- path of .rs file (relative to REPO root)
    outcome TEXT NOT NULL        -- 'ok' | 'error' | 'timeout'
);
CREATE INDEX idx_c2rust_compile_outcomes_rev ON c2rust_compile_outcomes(c2rust_rev);
CREATE INDEX idx_c2rust_compile_outcomes_run_at ON c2rust_compile_outcomes(run_at);

-- Per-file clippy outcomes for each c2rust_rev — populated by
-- scripts/check_c2rust_output_clippy.py, one row per (rs_file, run).
-- Mirrors c2rust_compile_outcomes' shape/rev-tagging discipline so
-- c2rust_regression_check.py can diff these rev-over-rev the same way,
-- but clippy warnings are individually interesting (lint name, span),
-- not just a pass/fail outcome, so each warning gets its own row rather
-- than a single count column — a file with 0 rows here at a given
-- (c2rust_rev, run_at) is a file that lint-checked clean, not a file
-- that was never checked (see checked_files/checked_at columns below
-- for that distinction, same "run happened but found nothing" problem
-- c2rust_decl_outcomes solves for translated decls).
CREATE TABLE c2rust_clippy_outcomes (
    id INTEGER PRIMARY KEY,
    c2rust_rev TEXT NOT NULL,    -- awtoau/c2rust git rev clippy-checked
    run_at TEXT NOT NULL,        -- ISO 8601, when this clippy run happened
    rs_file TEXT NOT NULL,       -- path of .rs file (relative to REPO root)
    lint_name TEXT NOT NULL,     -- e.g. 'clippy::needless_return', or
                                  -- 'compile_error' for a file that didn't
                                  -- reach the lint stage (SVH mismatch etc)
    level TEXT NOT NULL,         -- 'warning' | 'error'
    message TEXT NOT NULL,       -- clippy's rendered message, first line
    line INTEGER,                -- 1-based source line, if clippy gave a span
    col INTEGER                  -- 1-based source column, if clippy gave a span
);
CREATE INDEX idx_c2rust_clippy_outcomes_rev ON c2rust_clippy_outcomes(c2rust_rev);
CREATE INDEX idx_c2rust_clippy_outcomes_run_at ON c2rust_clippy_outcomes(run_at);
CREATE INDEX idx_c2rust_clippy_outcomes_lint ON c2rust_clippy_outcomes(lint_name);
CREATE INDEX idx_c2rust_clippy_outcomes_rsfile ON c2rust_clippy_outcomes(rs_file);

-- Which files were actually clippy-checked in a given run (independent
-- of how many warnings they produced — a clean file has 0 rows in
-- c2rust_clippy_outcomes above but must still show up as "checked" for
-- summary/regression purposes, same reasoning as c2rust_compile_outcomes
-- recording 'ok' explicitly rather than only ever recording errors).
CREATE TABLE c2rust_clippy_runs (
    id INTEGER PRIMARY KEY,
    c2rust_rev TEXT NOT NULL,
    run_at TEXT NOT NULL,
    rs_file TEXT NOT NULL,
    warning_count INTEGER NOT NULL,  -- rows in c2rust_clippy_outcomes for this (rev, run_at, rs_file)
    outcome TEXT NOT NULL            -- 'ok' (ran, 0+ warnings) | 'error' | 'timeout'
);
CREATE INDEX idx_c2rust_clippy_runs_rev ON c2rust_clippy_runs(c2rust_rev);
CREATE INDEX idx_c2rust_clippy_runs_run_at ON c2rust_clippy_runs(run_at);

-- Upstream immunant/c2rust intel: forks, issues, PRs — so before writing
-- our own fix we can check "has someone already solved this" in one
-- query instead of manually re-searching GitHub every time (2026-07-17:
-- "make a database of all known issue and forks issue and pr and
-- patchs so we can quickly check for existing code before we write our
-- own"). Populated by scripts/crawl_c2rust_upstream.py, NOT
-- wired into dev.py db (occasional/manual, like c2rust_attempts) —
-- preserved across build_db.py rebuilds the same way.
CREATE TABLE c2rust_forks (
    id INTEGER PRIMARY KEY,        -- GitHub repo id
    full_name TEXT NOT NULL UNIQUE, -- "owner/repo"
    html_url TEXT NOT NULL,
    pushed_at TEXT,                -- ISO 8601, last push — staleness signal
    ahead_by INTEGER,              -- commits ahead of immunant/c2rust master, if known
    stargazers_count INTEGER,
    default_branch TEXT,
    crawled_at TEXT NOT NULL
);
CREATE INDEX idx_c2rust_forks_pushed ON c2rust_forks(pushed_at);

CREATE TABLE c2rust_issues (
    id INTEGER PRIMARY KEY,        -- GitHub issue id (global, not per-repo number)
    repo TEXT NOT NULL,            -- "owner/repo" (immunant/c2rust or a fork)
    number INTEGER NOT NULL,
    title TEXT NOT NULL,
    state TEXT NOT NULL,           -- open | closed
    is_pr INTEGER NOT NULL,        -- 1 if this is actually a PR (GitHub's API unifies them)
    labels TEXT,                   -- comma-joined
    html_url TEXT NOT NULL,
    body TEXT,
    created_at TEXT,
    updated_at TEXT,
    closed_at TEXT,
    merged INTEGER,                -- PRs only: 1 if merged, 0 if closed-unmerged, NULL if open/not-a-PR
    crawled_at TEXT NOT NULL
);
CREATE INDEX idx_c2rust_issues_repo ON c2rust_issues(repo);
CREATE INDEX idx_c2rust_issues_state ON c2rust_issues(state);
CREATE INDEX idx_c2rust_issues_ispr ON c2rust_issues(is_pr);

-- One row per c2rust bug root-cause SHAPE, hand-curated from closed
-- awtoau/c2rust issues -- exists so a future triage/dispatch can query
-- "have we seen a failure signature/AST node kind like this before" and
-- get a real fix-location pointer instead of re-deriving the whole
-- investigation method from scratch every time (found 2026-07-18: 11
-- closed c2rust issues, each independently traced, no queryable record
-- of the accumulated method). Hand-curated, not auto-populated from
-- issue bodies -- the useful part is the classification judgement
-- (which layer, which AST node kind), not the raw text (c2rust_issues.
-- body already has that).
CREATE TABLE c2rust_fix_patterns (
    id INTEGER PRIMARY KEY,
    issue_repo TEXT NOT NULL,      -- "owner/repo", e.g. "awtoau/c2rust"
    issue_number INTEGER NOT NULL,
    layer TEXT NOT NULL,           -- ast-exporter | c_ast | cfg | translator | multiple
    fix_files TEXT NOT NULL,       -- comma-joined relative paths within the c2rust repo
    ast_node_kind TEXT,            -- e.g. "FileScopeAsmDecl", "TagImplicitCastExpr" -- NULL if not AST-node-specific
    failure_signature_pattern TEXT NOT NULL,  -- a substring/regex-ish description matching c2rust_failure_signatures.detail or the raw warning/error text, for lookup
    root_cause_summary TEXT NOT NULL,
    fix_summary TEXT NOT NULL,
    files_affected_at_discovery INTEGER,  -- how many corpus files hit this, when found -- a breadth signal for future prioritisation
    status TEXT NOT NULL DEFAULT 'fixed',  -- fixed | open | wontfix
    created_at TEXT NOT NULL
);
CREATE INDEX idx_c2rust_fixpat_layer ON c2rust_fix_patterns(layer);
CREATE INDEX idx_c2rust_fixpat_node ON c2rust_fix_patterns(ast_node_kind);

-- FTS5 full-text index over issue/PR title+body — the actual "check for
-- existing code before we write our own" search surface (e.g. MATCH
-- '"address of label" OR TagTypeUnknown OR AddrLabelExpr').
CREATE VIRTUAL TABLE c2rust_issues_fts USING fts5(
    repo, number UNINDEXED, title, body, content='c2rust_issues', content_rowid='id'
);

-- Time-series project-progress snapshots — NOT ephemeral, preserved
-- across build_db.py rebuilds same as the c2rust_* tables above (see
-- PERSISTENT_TABLES in build_db.py). One row per point-in-time
-- snapshot (taken via scripts/take_progress_snapshot.py, run manually
-- after landing a TU or a c2rust baseline run) so progress trends over
-- the project's actual history are queryable, not just current state.
CREATE TABLE progress_snapshots (
    id INTEGER PRIMARY KEY,
    taken_at TEXT NOT NULL,        -- ISO 8601
    note TEXT,                     -- optional free-text ("landed TU 29", "post-DFExpr-fix run")
    tus_landed INTEGER NOT NULL,
    corpus_total_files INTEGER,    -- lib/*.c files actually compiled into this kernel build
    corpus_total_loc INTEGER,
    landed_loc INTEGER,
    c2rust_clean INTEGER,          -- from the most recent c2rust_attempts run at snapshot time
    c2rust_crash INTEGER,
    c2rust_dropped_decls INTEGER,
    c2rust_no_output INTEGER,
    c2rust_timeout INTEGER,
    c2rust_rev TEXT
);
CREATE INDEX idx_progress_snapshots_taken_at ON progress_snapshots(taken_at);

-- Per-TU translation progress: manual (translated_tus) status joined
-- with the MOST RECENT c2rust_attempts row for that file, so one query
-- answers "what's done, how (manual/c2rust), and if c2rust failed, why"
-- — the relational progress table requested 2026-07-17.
CREATE VIEW tu_translation_progress AS
SELECT
  t.c_file,
  (tt.c_file IS NOT NULL) AS manually_translated,
  tt.rs_file, tt.landed_at, tt.patch_number,
  latest.outcome AS c2rust_outcome,
  latest.run_at AS c2rust_run_at,
  latest.warnings AS c2rust_warnings,
  latest.missing_top_level_nodes AS c2rust_missing_nodes,
  latest.label_address_exprs AS c2rust_label_addr_exprs,
  latest.c2rust_rev
FROM (SELECT DISTINCT c_file FROM c2rust_attempts
      UNION SELECT c_file FROM translated_tus) t
LEFT JOIN translated_tus tt ON tt.c_file = t.c_file
LEFT JOIN c2rust_attempts latest
  ON latest.c_file = t.c_file
  AND latest.run_at = (SELECT MAX(run_at) FROM c2rust_attempts WHERE c_file = t.c_file);

-- ---- convenience views (the point of "everything relational, reverse-
-- checkable" — where is X defined, where is X called FROM, is X already
-- translated, in one join, not grep) ----

-- Every function annotated with whether ITS OWN FILE is already
-- translated. This is the honest per-function translation-status join —
-- census functions don't map 1:1 to translated symbols (we translate
-- whole TUs), so "translated" here means "this function's source file
-- has a landed _rs.rs", not "this exact function has a Rust twin".
CREATE VIEW functions_with_status AS
SELECT f.*, (t.c_file IS NOT NULL) AS tu_translated, t.rs_file, t.landed_at
FROM functions f
LEFT JOIN translated_tus t
  ON t.c_file = f.file OR t.c_file = replace(f.file, 'linux-riscv/', '');

-- Best-effort resolved call edges: caller -> definition site(s), for
-- non-static callee names only (those are unambiguous — one file defines
-- each EXPORT_SYMBOL'd/extern name; `is_static` callees can collide
-- across TUs so are deliberately EXCLUDED here rather than silently
-- resolved to the wrong site — query `functions WHERE name=? AND
-- is_static=1` yourself and disambiguate by file/directory).
CREATE VIEW call_edges AS
SELECT
  caller.id   AS caller_id,   caller.file AS caller_file,   caller.name AS caller_name,
  callee.id   AS callee_id,   callee.file AS callee_file,   callee.name AS callee_name
FROM callees c
JOIN functions caller ON caller.id = c.function_id
JOIN functions callee ON callee.name = c.callee_name AND callee.is_static = 0;

-- Reverse lookup driver: for a translated TU, which of ITS census
-- functions' callees are themselves already translated (their file has a
-- landed _rs.rs) vs still C-only — a real dependency-readiness check,
-- not the vocabulary-overlap heuristic scripts/readiness.py uses.
CREATE VIEW tu_dependency_status AS
SELECT
  caller_file, caller_name, callee_file, callee_name,
  EXISTS (SELECT 1 FROM translated_tus t WHERE t.c_file = callee_file) AS callee_translated
FROM call_edges;

-- cscope-resolved call edges: supersedes `call_edges` for static callees
-- (which call_edges deliberately excludes — see its comment). A cscope
-- "call" ref's `context` column is the enclosing (caller) function; join
-- that against a cscope "definition" ref for the same name to get a
-- real, whole-corpus-resolved caller->definition-site edge, static or
-- not. Still honestly ambiguous when the SAME name is `static` in TWO+
-- files AND the caller's own file doesn't match either — those rows
-- surface with definition_ambiguous=1 rather than guessing.
CREATE VIEW cscope_call_edges AS
SELECT
  callref.file AS caller_file, callref.context AS caller_name,
  callref.name AS callee_name, callref.line AS call_line,
  defs.file AS callee_file, defs.line AS callee_line,
  (SELECT COUNT(*) FROM cscope_symbols d2
     WHERE d2.kind='definition' AND d2.name=callref.name) > 1 AS definition_ambiguous
FROM cscope_symbols callref
LEFT JOIN cscope_symbols defs
  ON defs.kind='definition' AND defs.name=callref.name
WHERE callref.kind='call';

-- Which statement families in the census are NOT yet backed by any rule's
-- match text (rough proxy via LIKE — a real matcher is scripts/readiness.py's
-- job; this view is for quick manual "what's uncovered" queries).
CREATE VIEW uncovered_hot_families AS
SELECT sf.fp, sf.instance_count, sf.exemplar_file, sf.exemplar_line, sf.exemplar_snippet
FROM statement_families sf
WHERE sf.instance_count > 10
  AND NOT EXISTS (
    SELECT 1 FROM rules r
    WHERE r.match_family IS NOT NULL AND sf.fp LIKE '%' || r.match_family || '%'
  )
ORDER BY sf.instance_count DESC;

-- Rule DB coverage summary by tier.
CREATE VIEW rule_tier_summary AS
SELECT tier, category, COUNT(*) AS n, SUM(deferred) AS n_deferred
FROM rules GROUP BY tier, category ORDER BY tier, category;

-- sparse's genuinely high-signal subset: __user/__iomem/__rcu address-
-- space misuse. Real-world measurement (2026-07-16, this corpus):
-- 214,271 total diagnostics, but 214,043 are 'warning' and dominated by
-- style noise this codebase doesn't care about (79% alone is "mixing
-- declarations and code", a C89-vs-later style check; a further chunk
-- is a false-positive-looking "non-constant initializer for static
-- object" this sparse build emits on plain integer-constant-expression
-- initializers). Only 651 rows are the address-space class sparse is
-- actually unique for — filter to THIS view, not the raw table, for
-- anything meant to inform a translation decision.
CREATE VIEW sparse_address_space_findings AS
SELECT file, line, col, severity, message FROM sparse_diagnostics
WHERE message LIKE '%address space%'
ORDER BY file, line;

-- Per-rule conformance check of c2rust's CURRENT raw output against each
-- of the 27 linux-rs rules: does c2rust already emit rule-conformant Rust
-- for a given construct (e.g. likely()/unlikely() hint already dropped
-- cleanly, rule 0007), or does it violate the rule (e.g. fls()/__fls()
-- transliterated as a literal bit-scan loop instead of the required
-- leading_zeros()-with-BITS-offset rewrite, rule 0006)? This is the
-- prioritization signal for future c2rust patch work — don't patch what's
-- already fine. Populated by scripts/check_c2rust_rule_conformance.py,
-- a current-state SNAPSHOT (each run replaces prior rows, unlike
-- c2rust_attempts' accumulating history) — but like c2rust_attempts this
-- is an occasional/manual analysis pass, not re-derived from the rules/
-- census on every routine build_db.py rebuild, so it gets the same
-- preserve-across-DB.unlink() treatment.
CREATE TABLE c2rust_rule_conformance (
    id INTEGER PRIMARY KEY,
    rule_id TEXT NOT NULL,         -- matches rules.id, e.g. "fls-family"
    c_file TEXT,                   -- relative to linux-riscv/, NULL if rule-level (not per-file)
    rust_file TEXT,                -- relative to repo root, NULL if rule-level
    line INTEGER,
    status TEXT NOT NULL,          -- conformant | violation | ambiguous | not_checkable | not_applicable
    detail TEXT NOT NULL,
    checked_at TEXT NOT NULL       -- ISO 8601, when this check run happened
);
CREATE INDEX idx_c2rust_ruleconf_rule ON c2rust_rule_conformance(rule_id);
CREATE INDEX idx_c2rust_ruleconf_status ON c2rust_rule_conformance(status);

-- Fix-prioritization queue: which rules have confirmed violations right
-- now, ranked by how many distinct files hit them — the concrete "patch
-- c2rust for this next" list.
CREATE VIEW c2rust_rule_violations_summary AS
SELECT rule_id, COUNT(*) AS n_violations, COUNT(DISTINCT rust_file) AS files_affected,
       GROUP_CONCAT(DISTINCT rust_file) AS example_files
FROM c2rust_rule_conformance
WHERE status = 'violation'
GROUP BY rule_id
ORDER BY files_affected DESC;

-- Authoritative documentation/reference sources — where to actually go
-- look up an API before guessing or reaching for a possibly-version-
-- mismatched external site. Two kinds: LOCAL (a path inside this
-- project's own trees — always version-correct by construction, since
-- it's the exact source this build compiles) and EXTERNAL (a URL —
-- convenient to browse, but only as trustworthy as its version_note
-- says, since e.g. rust.docs.kernel.org/6.12 or rust-for-linux.github.io
-- track a different commit than linux-riscv's actual vendored Linux 7.1
-- rust/kernel/ tree). Prefer LOCAL for anything version-sensitive
-- (exact macro/function signatures); EXTERNAL sources are fine for
-- browsing/searching but any concrete API detail taken from one should
-- be cross-checked against the LOCAL source before being relied on.
CREATE TABLE doc_sources (
    id INTEGER PRIMARY KEY,
    topic TEXT NOT NULL,           -- e.g. "rust-for-linux-kernel-crate", "c2rust-kernel-idiom-rules"
    kind TEXT NOT NULL,            -- local | external
    location TEXT NOT NULL,        -- LOCAL: repo-relative path. EXTERNAL: URL.
    version_note TEXT,             -- what this source tracks (a Linux version, a commit, "rolling/unknown — verify before trusting an exact signature")
    authoritative INTEGER NOT NULL DEFAULT 0,  -- 1 if this is the version-correct source of truth for `topic` in THIS project
    notes TEXT,
    added_at TEXT NOT NULL,        -- ISO 8601
    UNIQUE(topic, location)
);
CREATE INDEX idx_doc_sources_topic ON doc_sources(topic);
CREATE INDEX idx_doc_sources_authoritative ON doc_sources(authoritative);

-- Single source of truth for prioritizing and tracking work across BOTH
-- tracks (hand-translation in linux-riscv/, the awtoau/c2rust fork) —
-- not a replacement for GitHub issues/PRs as the actual handoff
-- mechanism (an agent, Copilot, or a human still does the work by
-- picking up a real issue/PR and opening a real commit), just the
-- queryable index of what exists, its priority, and its status, so
-- "what should be worked on next" is one query instead of scanning
-- multiple issue trackers and git logs by eye.
CREATE TABLE work_items (
    id INTEGER PRIMARY KEY,
    track TEXT NOT NULL,           -- c2rust | kernel | tooling | docs
    title TEXT NOT NULL,
    -- Optional link to the real handoff artifact — the actual place
    -- work happens. NULL means tracked here but not yet filed anywhere
    -- (e.g. a finding not yet worth a GitHub issue).
    repo TEXT,                     -- "owner/repo", e.g. "awtoau/c2rust"
    issue_number INTEGER,          -- GitHub issue/PR number in `repo`
    -- Denormalized priority, kept in sync with the real GitHub label
    -- (P0-P4, see c2rust_issues.labels) by whatever script/agent
    -- updates both — this column exists so kernel-track work items
    -- (which have no GitHub issue to carry a label) can still be
    -- ranked on the same P0-P4 scale.
    priority TEXT,                 -- P0 | P1 | P2 | P3 | P4
    status TEXT NOT NULL DEFAULT 'open',  -- open | in_progress | blocked | done | wontfix
    -- Why this priority — the concrete evidence (file count, boot-path
    -- relevance, etc.), not just a number, so re-ranking later has
    -- something to check against rather than re-deriving from scratch.
    priority_rationale TEXT,
    files_affected INTEGER,        -- corpus-breadth signal, when known
    blocks_boot_path INTEGER NOT NULL DEFAULT 0,  -- 1 if confirmed blocking a file linux-riscv actually compiles into its current kernel
    assigned_to TEXT,              -- "copilot" | "agent" | a person's name | NULL if unassigned
    fixed_by_commit TEXT,          -- commit hash, once done
    notes TEXT,
    created_at TEXT NOT NULL,      -- ISO 8601
    updated_at TEXT NOT NULL
);
CREATE INDEX idx_work_items_track ON work_items(track);
CREATE INDEX idx_work_items_priority ON work_items(priority);
CREATE INDEX idx_work_items_status ON work_items(status);
CREATE INDEX idx_work_items_repo_issue ON work_items(repo, issue_number);

-- Convenience view: what's actually actionable right now, ranked.
CREATE VIEW work_items_active AS
SELECT track, title, priority, status, repo, issue_number,
       files_affected, blocks_boot_path, assigned_to, priority_rationale
FROM work_items
WHERE status IN ('open', 'in_progress', 'blocked')
ORDER BY
    CASE priority WHEN 'P0' THEN 0 WHEN 'P1' THEN 1 WHEN 'P2' THEN 2
                   WHEN 'P3' THEN 3 WHEN 'P4' THEN 4 ELSE 5 END,
    blocks_boot_path DESC,
    files_affected DESC;

-- Per-file, per-tier validation history — the real answer to "what
-- stages has this file been through", queryable in one place instead of
-- cross-referencing c2rust_attempts/c2rust_compile_outcomes/
-- c2rust_rule_conformance/boot-history.csv/tmp/qemu-boot.log by hand
-- (found 2026-07-18: no such table existed; PLAN.md's 5-tier oracle
-- "records the highest tier passed" per instance was aspirational, not
-- actually implemented as queryable state).
--
-- Deliberately NOT the same axis as rule-conformance
-- (c2rust_rule_conformance) or SPDX/licensing checks
-- (check_spdx_provenance.py) — those check STYLE/CONVENTION/LICENSING
-- correctness (does this look like our idiom, does the export macro
-- match the C original's license), not BEHAVIORAL correctness (does the
-- translated code do the same thing as the C). A file can be fully
-- rule-conformant and still be behaviorally wrong; passing rule
-- conformance is not a tier here and must not be conflated with one.
--
-- One row per (file, tier) — a file's current status per tier, not a
-- run-history log (c2rust_attempts already serves that purpose for
-- tier-1-adjacent c2rust runs; this table is the DERIVED "where does
-- this file currently stand" summary, refreshed by whatever script owns
-- each tier's check, not hand-maintained).
CREATE TABLE file_oracle_status (
    id INTEGER PRIMARY KEY,
    c_file TEXT NOT NULL,          -- relative to linux-riscv/, e.g. "lib/bcd.c"
    population TEXT NOT NULL,      -- 'landed_tu' | 'c2rust_corpus' -- which pipeline produced the .rs being tracked; a file can appear in both (e.g. c2rust-clean AND later hand-landed)
    -- PLAN.md's 5 tiers, by number (1=compiles, 2=ABI/symbol diff,
    -- 3=KUnit differential, 4=boot+kselftest, 5=human review) --
    -- INTEGER not TEXT so "highest tier passed" is a plain MAX() query.
    tier INTEGER NOT NULL CHECK (tier BETWEEN 1 AND 5),
    status TEXT NOT NULL,          -- 'pass' | 'fail' | 'not_attempted' | 'not_applicable'
    detail TEXT,                   -- short human-readable evidence (e.g. "8 boots, 28 pairwise diffs byte-identical")
    evidence_ref TEXT,             -- pointer to the real artifact: a boot-log path, a commit hash, a GitHub issue/comment URL
    checked_at TEXT NOT NULL,      -- ISO 8601
    UNIQUE (c_file, population, tier)
);
CREATE INDEX idx_file_oracle_cfile ON file_oracle_status(c_file);
CREATE INDEX idx_file_oracle_tier ON file_oracle_status(tier);
CREATE INDEX idx_file_oracle_status ON file_oracle_status(status);

-- Convenience view: highest tier actually passed per file, so "how far
-- has this file gotten" is one row per file, not a manual MAX() each
-- time. NULL highest_tier_passed means every attempted tier failed (or
-- nothing has been attempted yet) -- check file_oracle_status directly
-- for the per-tier detail in that case.
CREATE VIEW file_oracle_summary AS
SELECT c_file, population,
       MAX(CASE WHEN status = 'pass' THEN tier END) AS highest_tier_passed,
       GROUP_CONCAT(CASE WHEN status = 'fail' THEN tier END) AS failed_tiers,
       MAX(checked_at) AS last_checked_at
FROM file_oracle_status
GROUP BY c_file, population;

-- ---- per-function safety-tier tracking (unsafe-baseline -> safe-verified) ----
--
-- Peer to file_oracle_status, not nested under it: file_oracle_status
-- answers "does this file's translation match the C oracle" (tier 1-5,
-- BEHAVIORAL correctness). This table answers a DIFFERENT question per
-- function: "how much of this function's C-parity Rust is expressible
-- without unsafe/raw-pointer/FFI escape hatches". A function can be
-- oracle tier-5 verified (behaviorally perfect) while still 100%
-- unsafe-baseline -- these are orthogonal axes, exactly as PLAN.md's
-- three-class unsafe policy and file_oracle_status's own tier column
-- are orthogonal to each other today.
--
-- Independent of translation_targets/target_id (docs/multi-arch-safety-
-- tier-tracking-plan-2026-07-19.md's arch/endian axis): the safe-lift
-- rules (0023/0024/0025) rewrite lock/refcount/ownership patterns that do
-- not vary by -march/-mabi/endianness, so this table is NOT keyed by
-- target_id. If a future safe-lift rule is found to be arch-conditional,
-- add target_id then -- do not speculatively add it now (same discipline
-- the multi-arch plan itself applies to translation_targets rows).
--
-- Grain is the FUNCTION, keyed (c_file, c_func_name, population) --
-- finer than file_oracle_status's (c_file, population) because a single
-- TU routinely mixes functions that are trivially safe (pure arithmetic)
-- with functions that must stay unsafe forever (MMIO/FFI), and a
-- file-level rollup would hide that mix. c_func_name is the C source
-- name (stable across a safe-lift rewrite of the SAME function -- the
-- lift changes the function's Rust body, not its identity); population
-- distinguishes landed_tu vs c2rust_corpus exactly as file_oracle_status
-- already does, because c2rust_corpus has no safe-lift output at all
-- today (c2rust only emits unsafe-baseline, per the multi-arch plan
-- §5) -- rows for that population will observationally never progress
-- past 'unsafe-baseline' until/unless that changes.
CREATE TABLE function_safety_status (
    id INTEGER PRIMARY KEY,
    c_file TEXT NOT NULL,          -- relative to linux-riscv/, e.g. "lib/bcd.c" (matches file_oracle_status.c_file)
    c_func_name TEXT NOT NULL,     -- the C declaration's name, e.g. "bcd2bin" (stable identity across safe-lift rewrites)
    population TEXT NOT NULL,      -- 'landed_tu' | 'c2rust_corpus', same vocabulary as file_oracle_status.population
    rs_func_name TEXT,             -- the emitted Rust fn name, when it differs from c_func_name (rare; NULL = same name)
    rs_file TEXT,                  -- path to the Rust source actually scanned for this row's state

    -- Mechanical pipeline state. Linear in the common case (each state
    -- supersedes the last for the SAME function) but state 2 is a
    -- terminal finding for functions that bypass 3/4 entirely -- a
    -- function mechanically found already-safe at state 1->2 has nothing
    -- left to "attempt" or "verify" beyond re-scanning after any future
    -- edit; it does not pass through 3/4 to reach a meaningful 5.
    --   1 unsafe-baseline               -- default for anything translated at all
    --   2 mechanically-checked-already-safe -- scanned: zero `unsafe` tokens, zero raw-pointer types in the fn body
    --   3 attempted-safe-conversion     -- a real rewrite onto kernel-crate safe wrapper types was tried (0023/0024/0025-style)
    --   4 safe-verified                 -- the attempted conversion PASSED a real file_oracle_status tier (see oracle_tier below)
    --   5 safe-with-exceptions          -- distinct terminal state: verified safe only under this project's
    --                                      already-accepted FFI/ABI-boundary exceptions (see accepted_exception_rule_id) --
    --                                      NOT a further step past safe-verified; a function is EITHER strict-safe (state 4,
    --                                      accepted_exception_rule_id IS NULL) OR safe-with-exceptions (state 5, NOT NULL),
    --                                      never both, because the exception is what stops it from ever reaching strict state 4.
    state TEXT NOT NULL CHECK (state IN (
        'unsafe-baseline',
        'mechanically-checked-already-safe',
        'attempted-safe-conversion',
        'safe-verified',
        'safe-with-exceptions'
    )),

    -- Populated only for state IN ('mechanically-checked-already-safe',
    -- 'attempted-safe-conversion', 'safe-verified', 'safe-with-exceptions')
    -- -- the raw counts backing the state-2 mechanical scan, kept even
    -- after a function progresses past state 2 so "why did the scanner
    -- call this safe" stays auditable without re-scanning history.
    unsafe_token_count INTEGER,        -- literal `unsafe` occurrences in the fn body (0 required for state >= 2)
    raw_pointer_count INTEGER,         -- *const T / *mut T occurrences in the fn signature+body (0 required for state >= 2)

    -- Which safe-lift rule(s) this conversion attempt applied, e.g.
    -- "safe-lift-lock-guard" -- NULL until state >= 3. Free text, not a
    -- strict FK, because a single conversion commonly applies more than
    -- one rule (lock-guard AND refcount in the same function); store the
    -- primary/first-applied rule id here and any others in `detail`.
    conversion_rule_id TEXT REFERENCES rules(id),

    -- The file_oracle_status tier this function's SAFE conversion passed
    -- (reusing file_oracle_status's existing 1-5 tier vocabulary
    -- verbatim, per instruction -- no parallel verification concept).
    -- This is NOT a join key back to a specific file_oracle_status row
    -- (that table is file-grained, this is function-grained, and a
    -- function's safe conversion may pass a tier before or after its
    -- file's unsafe-baseline does) -- it is the tier NUMBER the safe
    -- conversion was independently checked against, recorded here
    -- because file_oracle_status has no function-level column to hold
    -- it. Populated only for state IN ('safe-verified', 'safe-with-exceptions').
    oracle_tier INTEGER CHECK (oracle_tier IS NULL OR oracle_tier BETWEEN 1 AND 5),

    -- The "safe" here is qualified by an already-accepted project
    -- exception (rulesdb/rules/0018-c-abi-allocator-contract.toml is the
    -- canonical example: a kmalloc/kfree pair that crosses the C ABI
    -- MUST stay a raw-pointer FFI shim forever -- 0018 forbids lifting it
    -- to kernel::alloc types precisely because that would be WRONG, not
    -- merely unattempted). NULL means strict-safe: no accepted exception
    -- was invoked, the function is safe on its own terms. NOT NULL means
    -- state must be 'safe-with-exceptions', citing the specific rule
    -- (0018-style intrinsically-unsafe-boundary rule, or a future rule of
    -- the same shape) that licenses the remaining unsafe/FFI surface.
    accepted_exception_rule_id TEXT REFERENCES rules(id),

    loc INTEGER NOT NULL,          -- Rust fn body line count at scan time -- the weight for LOC% rollups (see views below);
                                    -- a 5-line and a 500-line safe function must NOT count equally in a coverage percentage
    detail TEXT,                   -- short human-readable note (e.g. "lifted to SpinLock<T>, second refcount left unsafe per 0018")
    evidence_ref TEXT,             -- pointer to the real artifact: commit hash, GitHub issue/comment URL (same vocabulary as file_oracle_status.evidence_ref)
    checked_at TEXT NOT NULL,      -- ISO 8601, when this row's state was last (re)computed by the scanner
    UNIQUE (c_file, c_func_name, population)
);
CREATE INDEX idx_func_safety_cfile ON function_safety_status(c_file);
CREATE INDEX idx_func_safety_state ON function_safety_status(state);
CREATE INDEX idx_func_safety_exception ON function_safety_status(accepted_exception_rule_id);

-- Per-file rollup: counts AND loc-weighted state, so "how safe is this
-- file" is one row, not a manual GROUP BY each time. loc_* columns sum
-- function-body LOC per state -- the basis for the LOC% figures the
-- coverage report needs (a file that is 90% functions-by-count safe but
-- those are all 3-line helpers next to one 400-line unsafe-baseline
-- function is NOT 90% safe by LOC, and this view is what exposes that).
CREATE VIEW function_safety_file_summary AS
SELECT
    c_file, population,
    COUNT(*)                                                          AS fn_count,
    SUM(loc)                                                          AS total_loc,
    SUM(CASE WHEN state = 'unsafe-baseline' THEN 1 ELSE 0 END)        AS fn_unsafe_baseline,
    SUM(CASE WHEN state = 'unsafe-baseline' THEN loc ELSE 0 END)      AS loc_unsafe_baseline,
    SUM(CASE WHEN state = 'mechanically-checked-already-safe' THEN 1 ELSE 0 END) AS fn_already_safe,
    SUM(CASE WHEN state = 'mechanically-checked-already-safe' THEN loc ELSE 0 END) AS loc_already_safe,
    SUM(CASE WHEN state = 'attempted-safe-conversion' THEN 1 ELSE 0 END) AS fn_attempted,
    SUM(CASE WHEN state = 'attempted-safe-conversion' THEN loc ELSE 0 END) AS loc_attempted,
    SUM(CASE WHEN state = 'safe-verified' THEN 1 ELSE 0 END)          AS fn_safe_verified,
    SUM(CASE WHEN state = 'safe-verified' THEN loc ELSE 0 END)        AS loc_safe_verified,
    SUM(CASE WHEN state = 'safe-with-exceptions' THEN 1 ELSE 0 END)   AS fn_safe_with_exceptions,
    SUM(CASE WHEN state = 'safe-with-exceptions' THEN loc ELSE 0 END) AS loc_safe_with_exceptions,
    -- strict-safe LOC% = (already-safe + safe-verified) / total, EXCLUDING safe-with-exceptions
    ROUND(100.0 * (
        SUM(CASE WHEN state = 'mechanically-checked-already-safe' THEN loc ELSE 0 END) +
        SUM(CASE WHEN state = 'safe-verified' THEN loc ELSE 0 END)
    ) / NULLIF(SUM(loc), 0), 1)                                        AS strict_safe_loc_pct,
    -- safe-with-exceptions-allowed LOC% = strict-safe PLUS safe-with-exceptions
    ROUND(100.0 * (
        SUM(CASE WHEN state = 'mechanically-checked-already-safe' THEN loc ELSE 0 END) +
        SUM(CASE WHEN state = 'safe-verified' THEN loc ELSE 0 END) +
        SUM(CASE WHEN state = 'safe-with-exceptions' THEN loc ELSE 0 END)
    ) / NULLIF(SUM(loc), 0), 1)                                        AS exceptions_allowed_loc_pct,
    MAX(checked_at)                                                    AS last_checked_at
FROM function_safety_status
GROUP BY c_file, population;

-- Per-subsection rollup: "subsection" = top-level directory component of
-- c_file (lib/, drivers/, fs/, kernel/, arch/riscv/, net/, mm/, ...).
-- Deliberately NOT a stored column or a parse of kernel Kconfig's
-- menu/endmenu structure -- see docs/safety-coverage-baseline-design-
-- 2026-07-19.md for the rejected Kconfig-menu alternative and why the
-- directory proxy was chosen instead. Derived here via SUBSTR/INSTR so
-- there is no redundant column to drift out of sync with c_file; arch/*
-- groups one level deeper (arch/riscv/ as a unit) because arch/ alone
-- spans every unrelated architecture in the tree.
CREATE VIEW function_safety_subsection_summary AS
SELECT
    CASE WHEN c_file LIKE 'arch/%'
         THEN substr(c_file, 1, instr(substr(c_file, 6), '/') + 5)
         ELSE substr(c_file, 1, instr(c_file, '/') - 1)
    END AS subsection,
    population,
    COUNT(*)                                                          AS fn_count,
    SUM(loc)                                                          AS total_loc,
    SUM(CASE WHEN state IN ('mechanically-checked-already-safe','safe-verified')
             THEN loc ELSE 0 END)                                     AS strict_safe_loc,
    SUM(CASE WHEN state IN ('mechanically-checked-already-safe','safe-verified','safe-with-exceptions')
             THEN loc ELSE 0 END)                                     AS exceptions_allowed_loc,
    ROUND(100.0 * SUM(CASE WHEN state IN ('mechanically-checked-already-safe','safe-verified')
             THEN loc ELSE 0 END) / NULLIF(SUM(loc), 0), 1)           AS strict_safe_loc_pct,
    ROUND(100.0 * SUM(CASE WHEN state IN ('mechanically-checked-already-safe','safe-verified','safe-with-exceptions')
             THEN loc ELSE 0 END) / NULLIF(SUM(loc), 0), 1)           AS exceptions_allowed_loc_pct
FROM function_safety_status
GROUP BY subsection, population;

-- Whole-corpus rollup: same LOC% formulas with no GROUP BY, for the
-- single top-of-report headline number.
CREATE VIEW function_safety_overall_summary AS
SELECT
    population,
    COUNT(*)                                                          AS fn_count,
    SUM(loc)                                                          AS total_loc,
    ROUND(100.0 * SUM(CASE WHEN state IN ('mechanically-checked-already-safe','safe-verified')
             THEN loc ELSE 0 END) / NULLIF(SUM(loc), 0), 1)           AS strict_safe_loc_pct,
    ROUND(100.0 * SUM(CASE WHEN state IN ('mechanically-checked-already-safe','safe-verified','safe-with-exceptions')
             THEN loc ELSE 0 END) / NULLIF(SUM(loc), 0), 1)           AS exceptions_allowed_loc_pct
FROM function_safety_status
GROUP BY population;
